mapper.select:
SELECT topic_id, topic_name, category, result_form, max_capacity, status, create_time
FROM topic_library
WHERE category = #{category}
ORDER BY topic_id
LIMIT #{limit} OFFSET #{offset}

SELECT topic_id, topic_name, category, result_form, max_capacity, status, create_time
FROM topic_library
WHERE topic_id = #{topicId}

SELECT t.max_capacity - (
    COALESCE(approved_count.approved_cnt, 0) +
    COALESCE(reserved_count.reserved_cnt, 0)
) AS remaining
FROM topic_library t
LEFT JOIN (
    SELECT topic_id, COUNT(*) AS approved_cnt
    FROM thesis_application
    WHERE application_status = 2 AND topic_id = #{topicId}
    GROUP BY topic_id
) approved_count ON t.topic_id = approved_count.topic_id
LEFT JOIN (
    SELECT topic_id, COUNT(*) AS reserved_cnt
    FROM thesis_application
    WHERE application_status = 1 AND topic_id = #{topicId}
    GROUP BY topic_id
) reserved_count ON t.topic_id = reserved_count.topic_id
WHERE t.topic_id = #{topicId}

mapper.update:
UPDATE topic_library
SET status = #{status}
WHERE topic_id = #{topicId}
